function solve(param) {
  const digitSum = n => {
    let sum = 0;
    while (n > 0) {
      sum += n % 10;
      n = Math.floor(n / 10);
    }
    return sum;
  };
  return param.sort((a, b) => {
    const sA = digitSum(a);
    const sB = digitSum(b);
    if (sA !== sB) return sA - sB;
    return a - b;
  });
}

